// --- SANITIZER FUNCTION ---
// این تابع از کرش کردن لاتکس در برابر کاراکترهای ویژه جلوگیری می‌کند
function escapeLatex(str) {
    if (!str) return "";
    return String(str)
        .replace(/\\/g, '\\textbackslash ')
        .replace(/_/g, '\\_')
        .replace(/&/g, '\\&')
        .replace(/%/g, '\\%')
        .replace(/\$/g, '\\$')
        .replace(/#/g, '\\#')
        .replace(/\{/g, '\\{')
        .replace(/\}/g, '\\}');
}

// --- TYPOGRAPHY RULES FUNCTION ---
// این تابع قوانین سخت‌گیرانه حروف‌چینی فارسی/انگلیسی را اعمال می‌کند
function applyPersianRules(str) {
    if (!str) return "";

    // قانون ۱: مدیریت اعداد و عبارات اعشاری (محصور کردن در \lr)
    // این Regex اعداد ورژن‌ها مثل 7.7.1.0 یا 2.x را پیدا کرده و درون \lr{} قرار می‌دهد.
    str = str.replace(/\b(\d+\.[a-zA-Z0-9.]+)\b/g, '\\lr{$1}');

    // قانون ۲: حذف پرانتز از دور عبارات انگلیسی چندکلمه‌ای
    // مثال: (SQL Injection) ->  SQL Injection 
    // اما عبارات تک کلمه‌ای مثل (CVE-123) دست‌نخورده باقی می‌مانند
    str = str.replace(/\(\s*([a-zA-Z0-9\-_]+(?:\s+[a-zA-Z0-9\-_]+)+)\s*\)/g, ' $1 ');

    // قانون ۳: ایجاد فاصله خالی قبل از دو نقطه (Colon) برای عبارات انگلیسی
    str = str.replace(/([a-zA-Z0-9])\s*:/g, '$1 :');

    return str;
}

const ai_results = $input.item.json.cve_list;
const original_cves = $('Execute a SQL query').all();
let total_cves = original_cves.length;

// ساخت هدر بر اساس قالب دقیق درخواست شده با فونت‌های لوکال
let latex = `\\documentclass[aspectratio=169,12pt]{beamer}
\\usetheme{Madrid}
\\usecolortheme{default}
\\setbeamertemplate{navigation symbols}{}

\\usepackage{microtype}
\\usepackage{booktabs}
\\usepackage{array}
\\usepackage{xcolor}
\\usepackage{xepersian}

% ------ Preamble: Font settings based on exactly available local .ttf files ------
\\settextfont
[Extension = .ttf,
UprightFont = Vazirmatn-FD-Regular,
BoldFont = Vazirmatn-FD-Bold]
{Vazirmatn-FD}

\\setdigitfont[Extension=.ttf]{Vazirmatn-FD-Regular}

% تنظیم فونت Sans الزامی برای قالب‌های Beamer
\\setsansfont
[Extension = .ttf,
UprightFont = Vazirmatn-FD-Regular,
BoldFont = Vazirmatn-FD-Bold]
{Vazirmatn-FD}

\\definecolor{DarkBlue}{RGB}{25,55,109}
\\setbeamercolor{title}{fg=DarkBlue}
\\setbeamercolor{frametitle}{fg=white,bg=DarkBlue}

\\title{گزارش آسیب‌پذیری‌های اختصاصی سازمان}
\\subtitle{تطبیق داده شده با دارایی‌های داخلی}
\\author{واحد امنیت اطلاعات}
\\date{\\today}

\\begin{document}
\\begin{frame}
  \\titlepage
\\end{frame}

\\begin{frame}{خلاصه مدیریتی}
  \\begin{itemize}
    \\item در پایش اخیر، تعداد \\lr{${total_cves}} آسیب‌پذیری بحرانی و مهم مرتبط با دارایی‌های سازمان شناسایی شد.
    \\item این گزارش نیازمند اقدام فوری توسط تیم‌های زیرساخت و شبکه می‌باشد.
  \\end{itemize}
  \\vspace{0.5cm}
  \\begin{center}
    \\begin{tabular}{cc}
      \\toprule
      شاخص & مقدار \\\\
      \\midrule
      تعداد کل آسیب‌پذیری‌های منطبق & \\lr{${total_cves}} \\\\
      \\bottomrule
    \\end{tabular}
  \\end{center}
\\end{frame}
`;

original_cves.forEach((orig_item, index) => {
    let db_data = orig_item.json;
    let cve_id = escapeLatex(db_data.cve_id || "Unknown");
    let score = escapeLatex(db_data.base_score || "N/A");
    let severity = escapeLatex(db_data.severity || "HIGH");

    let ai_text = ai_results[index].text || "{}";
    ai_text = ai_text.replace(/```json/gi, '').replace(/```/g, '').trim();

    let ai_data = { persian_summary: "خطا در ترجمه", mitigation_1: "-", mitigation_2: "-", mitigation_3: "-" };
    try {
        ai_data = JSON.parse(ai_text);
    } catch(e) {}

    // اعمال قوانین حروف‌چینی روی خروجی‌های هوش مصنوعی
    let summary = applyPersianRules(escapeLatex(ai_data.persian_summary));
    let mit1 = applyPersianRules(escapeLatex(ai_data.mitigation_1));
    let mit2 = applyPersianRules(escapeLatex(ai_data.mitigation_2));
    let mit3 = applyPersianRules(escapeLatex(ai_data.mitigation_3));

    // استخراج دارایی‌ها با رعایت قانون دوم (عدم استفاده از پرانتز برای کلمات انگلیسی)
    let assets = "نامشخص";
    if (db_data.affected_assets && db_data.affected_assets.length > 0) {
        let parsed_assets = typeof db_data.affected_assets === 'string' ? JSON.parse(db_data.affected_assets) : db_data.affected_assets;
        // بجای پرانتز از خط تیره برای جداسازی محصول و هاست استفاده شده است
        assets = parsed_assets.map(a => `\\lr{${escapeLatex(a.Hostname)}} - \\lr{${escapeLatex(a.Product)}}`).join(" ، ");
    }

    latex += `
\\begin{frame}{آسیب‌پذیری \\lr{${index + 1}}}
  {\\Large\\textbf{\\lr{${cve_id}}}}
  \\vspace{0.4cm}
  \\begin{itemize}
    \\item شدت : ${severity}
    \\item امتیاز CVSS : \\lr{${score}}
    \\item دارایی‌های تحت تأثیر : ${assets}
  \\end{itemize}
  \\vspace{0.3cm}
  \\textbf{شرح آسیب‌پذیری}

  ${summary}
\\end{frame}

\\begin{frame}{اقدامات پیشنهادی و کاهش ریسک}
  \\textbf{\\lr{${cve_id}}}
  \\vspace{0.4cm}
  \\begin{block}{اقدامات پیشنهادی}
    \\begin{itemize}
      \\item ${mit1}
      \\item ${mit2}
      \\item ${mit3}
    \\end{itemize}
  \\end{block}
\\end{frame}
`;
});

latex += `
\\begin{frame}{پایان گزارش}
  \\vfill
  \\begin{center}
    \\Large
    \\textcolor{DarkBlue}{\\textbf{پایان گزارش - لطفا جهت رفع موارد اقدام نمایید.}}
  \\end{center}
\\end{frame}
\\end{document}
`;

return [{ json: { final_latex: latex } }];
